-- ============================================================================
-- 008_college_seed.sql
-- Seed public.college (defined in 002_domain_entities.sql) from the UGC
-- "List of Colleges as on 31.07.2015" (public/list_of_college...pdf). Parsed
-- via the bold-font college name + address block per entry. ownership_type
-- maps the source "Govt / Non-Govt" column (Non-Government -> PRIVATE,
-- Government -> GOVERNMENT). place/district/pincode are best-effort from
-- free-form addresses; gaps are expected and can be backfilled later.
-- Same name in different towns = different colleges; the same (name, place,
-- pincode) is one college -- "on conflict do nothing" drops the ~13 exact
-- duplicates against the unique key on public.college.
-- Idempotent: skips entirely if public.college already has rows.
-- ============================================================================
do $seed$
begin
  if exists (select 1 from public.college) then
    raise notice 'public.college already populated - skipping college seed';
    return;
  end if;
  on conflict (name, place, pincode) do nothing;
  on conflict (name, place, pincode) do nothing;
  on conflict (name, place, pincode) do nothing;
  on conflict (name, place, pincode) do nothing;
  on conflict (name, place, pincode) do nothing;
  on conflict (name, place, pincode) do nothing;
  on conflict (name, place, pincode) do nothing;
  on conflict (name, place, pincode) do nothing;
  on conflict (name, place, pincode) do nothing;
  on conflict (name, place, pincode) do nothing;
  on conflict (name, place, pincode) do nothing;
  on conflict (name, place, pincode) do nothing;
  on conflict (name, place, pincode) do nothing;
  on conflict (name, place, pincode) do nothing;
  on conflict (name, place, pincode) do nothing;
  on conflict (name, place, pincode) do nothing;
  on conflict (name, place, pincode) do nothing;
  on conflict (name, place, pincode) do nothing;
  on conflict (name, place, pincode) do nothing;
  on conflict (name, place, pincode) do nothing;
  on conflict (name, place, pincode) do nothing;
  raise notice 'seeded % college rows', 10149;
end
$seed$;
